const item = $input.first();

return [{
  json: {
    definition_mode: item.json.body?.definition_mode || "AI"
  },
  binary: {
    table_a: item.binary.table_a,
    table_b: item.binary.table_b
  }
}];

const grouped = {};

for (const row of $input.all().map(i => i.json)) {
  const order =
    row["Case Key"] ||
    row.Ebeln ||
    row.Order_Number ||
    row["Purchase Order"];

  if (!order) continue;
  if (!grouped[order]) grouped[order] = [];
  grouped[order].push(row);
}

return Object.entries(grouped).map(([order, acts]) => ({
  json: { Order_Number: order, activities: acts }
}));

return $input.all().map(item => {

  const acts = item.json.activities;

  const sorted = [...acts].sort(
    (a,b) => new Date(a.Eventtime) - new Date(b.Eventtime)
  );

  const flow = [];

  for (const a of sorted) {

    const name =
      (a["Activity En"] ||
       a["Activity De"] ||
       "").toLowerCase().trim();

    if (name) flow.push(name);

  }

  return {
    json: {
      ...item.json,
      Actual_Flow: flow
    }
  };

});

const allOrders = $input.all().map(i => i.json);

const actCounts = {};
allOrders.forEach(o => {
  const uniqueActs = [...new Set(o.Actual_Flow || [])];
  uniqueActs.forEach(a => { actCounts[a] = (actCounts[a] || 0) + 1; });
});

const activities = Object.entries(actCounts)
  .sort((a, b) => b[1] - a[1])
  .map(([act]) => act)
  .slice(0, 30);

return [{ json: { activities, total_orders: allOrders.length, all_so_data: allOrders } }];

const item = $input.first();

let msg = "";

// Extract AI response
if (item.json.message?.content) {
  msg = item.json.message.content;
} else if (item.json.choices?.[0]?.message?.content) {
  msg = item.json.choices[0].message.content;
} else if (typeof item.json === "string") {
  msg = item.json;
}

if (!msg) throw new Error("AI response missing");

// Extract JSON block
const jsonMatch = msg.match(/\{[\s\S]*\}/);
if (!jsonMatch) throw new Error("No JSON found in AI response");

let jsonString = jsonMatch[0]
  .replace(/\/\/.*$/gm, "")
  .replace(/,\s*}/g, "}")
  .replace(/,\s*]/g, "]")
  .replace(/}\s*{/g, "},{")
  .replace(/'/g, '"')
  .replace(/\n/g, " ")
  .replace(/approve purchase order[^"]*/g, "approve purchase order");

let parsed;

try {
  parsed = JSON.parse(jsonString);
} catch (e) {
  console.log("RAW AI OUTPUT:", msg);
  throw new Error("AI JSON parsing failed: " + e.message);
}


// Normalization helper
const normalize = (arr) => {
  if (!Array.isArray(arr)) return [];
  return arr
    .map(v => {
      let value = "";

      if (typeof v === "string") value = v;

      else if (typeof v === "object" && v !== null) {
        value = v.activity || v.name || Object.values(v)[0] || "";
      }

      else value = String(v);

      return value.toLowerCase().trim();
    })
    .filter(Boolean);
};


// Load real orders
const orders = $items("Cleaning2")[0].json.all_so_data;


// Detect available steps from data
const availableSteps = new Set(
  orders.flatMap(o => o.Actual_Flow || [])
);


// Filter AI hallucinations
const standard = normalize(parsed.standard_flow || [])
  .filter(s => availableSteps.has(s));

const critical = normalize(parsed.critical_steps || [])
  .filter(s => availableSteps.has(s));


// Attach to every order
return orders.map(o => ({
  json: {
    ...o,
    Standard_Flow: standard,
    Critical_Steps: critical
  }
}));

// ─────────────────────────────────────────────────────────────────────────────
// FIXED Deviation Engine
// Uses AI-defined Standard_Flow + Critical_Steps instead of hardcoded names.
// Fuzzy matching handles variant activity name spellings.
// ─────────────────────────────────────────────────────────────────────────────
const items = $input.all();

return items.map(item => {
  const order        = item.json;
  const standardFlow = order.Standard_Flow  || [];
  const actualFlow   = order.Actual_Flow    || [];
  const criticalSteps = order.Critical_Steps || [];
  const deviations   = [];
  let blocked = false, blockReason = '', blockStep = '';

  // Skip stub orders with fewer than 2 activities — nothing meaningful to check
  if (actualFlow.length < 2) {
    return {
      json: {
        ...order,
        Deviations_Array:  [],
        Deviation_Count:   0,
        Deviation_Types:   'None',
        Deviation_Counts:  { CRITICAL: 0, HIGH: 0, MEDIUM: 0, LOW: 0 },
        Risk_Score:        0,
        Risk_Level:        'LOW',
        Process_Status:    'PASS',
        Status_Label:      'Compliant',
        Blocked:           false,
        Block_Reason:      '',
        Block_Step:        '',
        Total_Deviations:  0
      }
    };
  }

  // ── 1. Missing critical steps (CRITICAL severity → BLOCKED) ──────────────
  for (const step of criticalSteps) {
    if (!actualFlow.includes(step)) {
      deviations.push({
        Type:        'MISSING_CRITICAL_STEP',
        step:        step,
        severity:    'CRITICAL',
        detected_at: 'END_OF_PROCESS',
        position:    standardFlow.indexOf(step) + 1 || 0
      });
      if (!blocked) {
        blocked     = true;
        blockReason = `Critical step not completed: ${step}`;
        blockStep   = step;
      }
    }
  }

  // ── 2. PO / item deletion (fuzzy match on actual step names) ─────────────
  const deleteStep = actualFlow.find(s =>
    s.includes('delet') &&
    (s.includes('order') || s.includes('item') || s.includes('po') || s.includes('purchas'))
  );
  if (deleteStep && !deviations.find(d => d.step === deleteStep)) {
    deviations.push({
      Type:        'PO_DELETED',
      step:        deleteStep,
      severity:    'HIGH',
      detected_at: deleteStep,
      position:    actualFlow.indexOf(deleteStep) + 1
    });
    if (!blocked) {
      blocked     = true;
      blockReason = 'Purchase order item was deleted';
      blockStep   = deleteStep;
    }
  }

  // ── 3. Value / quantity / price changes ──────────────────────────────────
  const changeStep = actualFlow.find(s =>
    (s.includes('change') || s.includes('modif') || s.includes('updat') || s.includes('revis')) &&
    (s.includes('qty') || s.includes('quant') || s.includes('price') ||
     s.includes('amount') || s.includes('value') || s.includes('cost'))
  );
  if (changeStep && !deviations.find(d => d.step === changeStep)) {
    deviations.push({
      Type:        'VALUE_CHANGE',
      step:        changeStep,
      severity:    'MEDIUM',
      detected_at: changeStep,
      position:    actualFlow.indexOf(changeStep) + 1
    });
  }

  // ── 4. Steps executed out of order vs. standard flow ─────────────────────
  const actualInStandard = actualFlow.filter(s => standardFlow.includes(s));
  for (let i = 0; i < actualInStandard.length - 1; i++) {
    const idxA = standardFlow.indexOf(actualInStandard[i]);
    const idxB = standardFlow.indexOf(actualInStandard[i + 1]);
    if (idxA !== -1 && idxB !== -1 && idxA > idxB) {
      const outStep = actualInStandard[i + 1];
      if (!deviations.find(d => d.Type === 'OUT_OF_ORDER' && d.step === outStep)) {
        deviations.push({
          Type:        'OUT_OF_ORDER',
          step:        outStep,
          severity:    'HIGH',
          detected_at: outStep,
          position:    actualFlow.indexOf(outStep) + 1
        });
      }
    }
  }

  // ── 5. Skipped non-critical standard steps ────────────────────────────────
  // Only flag when order has completed at least half the expected standard steps
  const completedStandardCount = standardFlow.filter(s => actualFlow.includes(s)).length;
  if (standardFlow.length > 0 && completedStandardCount >= Math.ceil(standardFlow.length / 2)) {
    for (const step of standardFlow) {
      if (!criticalSteps.includes(step) && !actualFlow.includes(step)) {
        if (!deviations.find(d => d.step === step)) {
          deviations.push({
            Type:        'SKIPPED_STEP',
            step:        step,
            severity:    'LOW',
            detected_at: 'END_OF_PROCESS',
            position:    standardFlow.indexOf(step) + 1
          });
        }
      }
    }
  }

  // ── Compute risk scores ───────────────────────────────────────────────────
  const critCount = deviations.filter(d => d.severity === 'CRITICAL').length;
  const highCount = deviations.filter(d => d.severity === 'HIGH').length;
  const medCount  = deviations.filter(d => d.severity === 'MEDIUM').length;
  const lowCount  = deviations.filter(d => d.severity === 'LOW').length;

  const riskScore = (critCount * 20) + (highCount * 10) + (medCount * 5) + (lowCount * 2);
  const riskLevel = critCount > 0 ? 'CRITICAL'
    : highCount > 0 ? 'HIGH'
    : medCount  > 0 ? 'MEDIUM'
    : lowCount  > 0 ? 'LOW'
    : 'LOW';
  const processStatus = blocked           ? 'BLOCKED'
    : deviations.length > 0 ? 'ALERT'
    : 'PASS';

  return {
    json: {
      ...order,
      Deviations_Array:  deviations,
      Deviation_Count:   deviations.length,
      Deviation_Types:   [...new Set(deviations.map(d => d.Type))].join(', ') || 'None',
      Deviation_Counts:  { CRITICAL: critCount, HIGH: highCount, MEDIUM: medCount, LOW: lowCount },
      Risk_Score:        riskScore,
      Risk_Level:        riskLevel,
      Process_Status:    processStatus,
      Status_Label:      processStatus === 'BLOCKED' ? 'Process Blocked'
                       : processStatus === 'ALERT'   ? 'Alert - Review Required'
                       : 'Compliant',
      Blocked:           blocked,
      Block_Reason:      blockReason,
      Block_Step:        blockStep,
      Total_Deviations:  deviations.length
    }
  };
});

// Only send BLOCKED/ALERT orders to AI RCA — PASS orders don't need it
return $input.all().filter(item => {
  const status         = item.json.Process_Status;
  const deviationCount = item.json.Total_Deviations || 0;
  return status === 'BLOCKED' || status === 'ALERT' || deviationCount > 0;
});

