const originalItems = $items("Limit1");
const originalMap = {};
for (const orig of originalItems) {
  const key = orig.json.Order_Number;
  if (key) originalMap[key] = orig.json;
}

// Build AI results map keyed by Order_Number from INSIDE the AI response
const aiMap = {};
$input.all().forEach((item) => {
  try {
    const msg =
      item.json.message?.content ||
      item.json.choices?.[0]?.message?.content ||
      "";

    const match = msg.match(/\{[\s\S]*\}/);
    if (match) {
      let cleaned = match[0]
        .replace(/\/\/.*$/gm, "")
        .replace(/,\s*}/g, "}")
        .replace(/,\s*]/g, "]")
        .replace(/'/g, '"')
        .replace(/\n/g, " ");
      const parsed = JSON.parse(cleaned);

      // Use Order_Number from inside the AI response — reliable even with batching
      const orderNum = parsed.Order_Number || item.json.Order_Number;
      if (orderNum && (parsed.root_cause || parsed.business_risk)) {
        aiMap[orderNum] = parsed;
      }
    }
  } catch (e) {}
});

// Return ALL original Limit1 items with AI data merged in where available
return originalItems.map((orig) => {
  const orderNum = orig.json.Order_Number;
  const ai = aiMap[orderNum] || {};
  return {
    json: {
      ...orig.json,
      root_cause:     ai.root_cause     || "",
      business_risk:  ai.business_risk  || "",
      recommendation: ai.recommendation || ""
    }
  };
});

// RCA lookup from the AI-processed orders
const rcaMap = {};
$input.all().forEach(item => {
  if (item.json.Order_Number) rcaMap[item.json.Order_Number] = {
    root_cause:     item.json.root_cause     || '',
    business_risk:  item.json.business_risk  || '',
    recommendation: item.json.recommendation || ''
  };
});

// ALL orders from Deviation Engine (includes PASS orders)
const allOrders = $items('Deviation Engine3').map(i => i.json);

return allOrders.map((json, index) => {
  const rca        = rcaMap[json.Order_Number] || {};
  const deviations = json.Deviations_Array || [];
  const dc         = json.Deviation_Counts || {};
  const devCounts  = (dc.CRITICAL || dc.HIGH || dc.MEDIUM || dc.LOW) ? dc : {
    CRITICAL: deviations.filter(d => d.severity === 'CRITICAL').length,
    HIGH:     deviations.filter(d => d.severity === 'HIGH').length,
    MEDIUM:   deviations.filter(d => d.severity === 'MEDIUM').length,
    LOW:      deviations.filter(d => d.severity === 'LOW').length
  };

  const actualFlow    = json.Actual_Flow    || [];
  const standardFlow  = json.Standard_Flow  || [];
  const criticalSteps = json.Critical_Steps || [];
  const activities    = json.activities     || [];
  const dates         = activities.map(a => a.Eventtime).filter(Boolean).sort();
  const orderDate     = dates[0] ? dates[0].substring(0, 10) : '';

  const timeline = actualFlow.map((step, i) => ({
    step_number: i + 1,
    step_name:   step,
    decision: (json.Block_Step && step === json.Block_Step) ? 'BLOCK' : 'ALLOW',
    reason:   (json.Block_Step && step === json.Block_Step) ? json.Block_Reason : ''
  }));

  return {
    json: {
      Order_Number:           json.Order_Number || `ORD-${1000 + index}`,
      Customer:               '',
      Order_Date:             orderDate,
      Process_Status:         json.Process_Status  || 'PASS',
      Risk_Level:             json.Risk_Level       || 'LOW',
      Risk_Score:             json.Risk_Score       || 0,
      Status_Label:           json.Status_Label     || 'Compliant',
      Total_Steps:            actualFlow.length,
      Completed_Steps:        actualFlow.length,
      Deviation_Count:        deviations.length,
      Deviation_Types:        json.Deviation_Types  || 'None',
      Deviations_Array:       deviations,
      Deviation_Counts:       devCounts,
      Missing_Critical_Steps: [],
      Blocked:                json.Blocked      || false,
      Block_Reason:           json.Block_Reason || '',
      Block_Step:             json.Block_Step   || '',
      Block_Position:         json.Block_Step ? actualFlow.indexOf(json.Block_Step) + 1 : -1,
      Actual_Flow:            actualFlow,
      Standard_Flow:          standardFlow,
      Critical_Steps:         criticalSteps,
      Step_By_Step_Timeline:  timeline,
      root_cause:             rca.root_cause     || '',
      business_risk:          rca.business_risk  || '',
      recommendation:         rca.recommendation || ''
    }
  };
});

const all = $input.all().map(i => i.json);

return [{
  json: {
    status: "success",
    totalOrders: all.length,
    heatmap: {
      CRITICAL: all.filter(o => o.Risk_Level === "CRITICAL").length,
      HIGH:     all.filter(o => o.Risk_Level === "HIGH").length,
      MEDIUM:   all.filter(o => o.Risk_Level === "MEDIUM").length,
      LOW:      all.filter(o => o.Risk_Level === "LOW").length
    },
    statusSummary: {
      BLOCKED: all.filter(o => o.Process_Status === "BLOCKED").length,
      ALERT:   all.filter(o => o.Process_Status === "ALERT").length,
      PASS:    all.filter(o => o.Process_Status === "PASS").length
    },
    insights: all
      .filter(o => o.Process_Status !== "PASS")
      .sort((a, b) => (b.Risk_Score || 0) - (a.Risk_Score || 0))
      .slice(0, 10),
    orders: all
  }
}];
